	@Test
	void emptyMetadataDisablesSchemaAndFederationFacts() {
		RewriteMetadata metadata = RewriteMetadata.empty();

		assertFalse(metadata.completeForDataset());
		assertFalse(metadata.closureFreshEnough());
		assertTrue(metadata.closureFreshnessTimestamp().isEmpty());
		assertTrue(metadata.entailmentMode().isEmpty());
		assertTrue(metadata.completeGraphUniverse().isEmpty());
		assertTrue(metadata.completePredicateUniverse().isEmpty());
		assertTrue(metadata.completeEndpointSet("endpoint").isEmpty());
	}

	private static RewriteCertificate certificate(RewriteSafety safety) {
		return new RewriteCertificate("rule", "old", "new", safety,
				Set.of(RewriteAssumption.STANDARD_SPARQL_SEMANTICS));
	}
